<template><div class="switcher" role="navigation" aria-label="原型方案切换"><button aria-label="上一方案" @click="move(-1)">←</button><span><b>{{ current }}</b> · {{ labels[current] }}</span><button aria-label="下一方案" @click="move(1)">→</button></div></template>
<script setup lang="ts">const props=defineProps<{current:'A'|'B'|'C';labels:Record<'A'|'B'|'C',string>}>();const emit=defineEmits<{change:[value:'A'|'B'|'C']}>();const keys=['A','B','C']as const;function move(delta:number){const index=keys.indexOf(props.current);emit('change',keys[(index+delta+keys.length)%keys.length])}</script>
<style scoped>.switcher{position:fixed;z-index:20;bottom:20px;left:50%;display:flex;align-items:center;gap:12px;padding:8px 10px;color:#fff7e7;background:#0d111ded;border:1px solid #dfb16699;border-radius:999px;box-shadow:0 12px 36px #0005;backdrop-filter:blur(14px);transform:translateX(-50%)}.switcher span{min-width:134px;text-align:center;font-size:13px}.switcher b{color:#e4b76e}.switcher button{width:30px;height:30px;color:inherit;background:transparent;border:0;border-radius:50%;font-size:20px;cursor:pointer}.switcher button:hover{background:#fff2}</style>
